SELECT id, email, name, status, created_on, role FROM users
AND name LIKE '%' || #{name} || '%'
AND status = TRIM(#{status})
AND TRUNC(created_on) >= #{startDate}
AND TRUNC(created_on) <= #{endDate}
AND role != #{excludeRoleId}
ORDER BY created_on DESC

SELECT COUNT(*)
FROM users
WHERE email = #{email}

